const bridgeBaseUrl = 'http://100.116.103.78:8090';
const bridgeApiKey = '';
const expectedMinCompanies = 11;

const companies = [{"name": "Anthropic", "tier": 2, "ats": "greenhouse", "board_id": "anthropic", "title_filter": ["solutions", "engineer", "architect", "technical", "account", "sales"]}, {"name": "OpenAI", "tier": 2, "ats": "ashby", "board_id": "openai", "title_filter": ["deployment", "solutions engineer", "solution engineer", "forward deployed", "architect", "pre-sales"]}, {"name": "Postman", "tier": 1, "ats": "greenhouse", "board_id": "postman", "title_filter": ["solutions", "engineer", "architect", "technical"]}, {"name": "Aisera", "tier": 1, "ats": "greenhouse", "board_id": "aisera", "title_filter": ["solutions", "engineer", "sales", "architect"]}, {"name": "Miro", "tier": 1, "ats": "greenhouse", "board_id": "miro", "title_filter": ["solutions", "engineer", "architect", "customer"]}, {"name": "Airtable", "tier": 1, "ats": "greenhouse", "board_id": "airtable", "title_filter": ["solutions", "engineer", "architect", "technical account"]}, {"name": "Smartsheet", "tier": 1, "ats": "greenhouse", "board_id": "smartsheet", "title_filter": ["solutions", "engineer", "architect", "customer"]}, {"name": "Cohere", "tier": 2, "ats": "greenhouse", "board_id": "cohere", "title_filter": ["solutions", "engineer", "architect", "technical account"]}, {"name": "Glean", "tier": 2, "ats": "greenhouse", "board_id": "gleanwork", "title_filter": ["solutions", "engineer", "architect", "customer"]}, {"name": "Writer", "tier": 2, "ats": "greenhouse", "board_id": "writer", "title_filter": ["solutions", "engineer", "architect", "sales"]}, {"name": "Atlassian", "tier": 2, "ats": "greenhouse", "board_id": "atlassian", "title_filter": ["solutions", "developer", "architect", "technical account"]}, {"name": "Workato", "tier": 2, "ats": "greenhouse", "board_id": "workato", "title_filter": ["solutions", "engineer", "architect", "automation"]}, {"name": "Datadog", "tier": 2, "ats": "greenhouse", "board_id": "datadog", "title_filter": ["solutions", "engineer", "architect", "technical account"]}];

const companyListWarning = companies.length < expectedMinCompanies
  ? `career_page_company_list_low:${companies.length} (expected >= ${expectedMinCompanies})`
  : null;

return companies.map((company) => ({
  json: {
    company,
    bridge_base_url: bridgeBaseUrl,
    bridge_api_key: bridgeApiKey,
    delay_seconds: 2,
    similarity_threshold: 0.92,
    company_list_count: companies.length,
    company_list_warning: companyListWarning,
  },
}));

const output = [];

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

for (const item of $input.all()) {
  const company = item.json.company || {};
  const result = {
    ...item.json,
    fetch_url: null,
    fetched_jobs: 0,
    raw_jobs: [],
    fetch_error: null,
  };

  try {
    const ats = String(company.ats || '').toLowerCase();

    if (ats === 'greenhouse') {
      const boardId = String(company.board_id || '').trim();
      if (!boardId) {
        throw new Error('Missing board_id for greenhouse company ' + company.name);
      }
      const url = 'https://boards-api.greenhouse.io/v1/boards/' + encodeURIComponent(boardId) + '/jobs';
      result.fetch_url = url;
      const response = await fetch(url, { headers: { accept: 'application/json' } });
      if (!response.ok) {
        throw new Error('HTTP ' + response.status + ' from ' + url);
      }
      const payload = await response.json();
      const jobs = Array.isArray(payload.jobs) ? payload.jobs : [];
      result.raw_jobs = jobs;
      result.fetched_jobs = jobs.length;
    } else if (ats === 'ashby') {
      const boardId = String(company.board_id || '').trim();
      if (!boardId) {
        throw new Error('Missing board_id for ashby company ' + company.name);
      }
      const url = 'https://api.ashbyhq.com/posting-api/job-board/' + encodeURIComponent(boardId);
      result.fetch_url = url;
      const response = await fetch(url, { headers: { accept: 'application/json' } });
      if (!response.ok) {
        throw new Error('HTTP ' + response.status + ' from ' + url);
      }
      const payload = await response.json();
      const jobs = Array.isArray(payload.jobs) ? payload.jobs : [];
      result.raw_jobs = jobs;
      result.fetched_jobs = jobs.length;
    } else if (ats === 'lever') {
      const boardId = String(company.board_id || '').trim();
      if (!boardId) {
        throw new Error('Missing board_id for lever company ' + company.name);
      }
      const url = 'https://api.lever.co/v0/postings/' + encodeURIComponent(boardId) + '?mode=json';
      result.fetch_url = url;
      const response = await fetch(url, { headers: { accept: 'application/json' } });
      if (!response.ok) {
        throw new Error('HTTP ' + response.status + ' from ' + url);
      }
      const payload = await response.json();
      const jobs = Array.isArray(payload) ? payload : [];
      result.raw_jobs = jobs;
      result.fetched_jobs = jobs.length;
    } else {
      result.fetch_error = 'Unsupported ATS: ' + ats;
    }
  } catch (error) {
    result.fetch_error = error && error.message ? error.message : String(error);
  }

  output.push({ json: result });

  const delaySeconds = Number(item.json.delay_seconds || 2);
  await sleep(Math.max(0, delaySeconds) * 1000);
}

return output;

function normalizeText(value) {
  return String(value || '').trim();
}

function titleMatches(title, filters) {
  const text = normalizeText(title).toLowerCase();
  if (!text) return false;
  const terms = Array.isArray(filters) ? filters : [];
  if (terms.length === 0) return true;
  return terms.some((term) => text.includes(String(term || '').toLowerCase()));
}

const output = [];

for (const item of $input.all()) {
  const company = item.json.company || {};
  const ats = String(company.ats || '').toLowerCase();
  const filters = Array.isArray(company.title_filter) ? company.title_filter : [];
  const rawJobs = Array.isArray(item.json.raw_jobs) ? item.json.raw_jobs : [];

  const normalized = [];
  if (!item.json.fetch_error) {
    for (const job of rawJobs) {
      if (!job || typeof job !== 'object') continue;

      if (ats === 'greenhouse') {
        const title = normalizeText(job.title);
        if (!titleMatches(title, filters)) continue;
        normalized.push({
          title,
          company: company.name,
          location: normalizeText(job.location && job.location.name),
          url: normalizeText(job.absolute_url),
          description: '',
          source: 'career_page',
          search_query: String(company.name || '') + ' careers',
          company_tier: Number(company.tier || 0),
          date_posted: job.updated_at || null,
        });
      } else if (ats === 'ashby') {
        const title = normalizeText(job.title);
        if (!titleMatches(title, filters)) continue;
        normalized.push({
          title,
          company: company.name,
          location: normalizeText(job.location),
          url: normalizeText(job.jobUrl || job.applyUrl),
          description: normalizeText(job.descriptionPlain || job.descriptionHtml),
          source: 'career_page',
          search_query: String(company.name || '') + ' careers',
          company_tier: Number(company.tier || 0),
          date_posted: job.publishedAt || null,
        });
      } else if (ats === 'lever') {
        const title = normalizeText(job.text);
        if (!titleMatches(title, filters)) continue;
        normalized.push({
          title,
          company: company.name,
          location: normalizeText(job.categories && job.categories.location),
          url: normalizeText(job.hostedUrl),
          description: normalizeText(job.descriptionPlain || job.description),
          source: 'career_page',
          search_query: String(company.name || '') + ' careers',
          company_tier: Number(company.tier || 0),
          date_posted: job.createdAt || null,
        });
      }
    }
  }
  const capped = normalized.slice(0, 20);
  output.push({
    json: {
      ...item.json,
      normalized_jobs: capped,
      matched_jobs: capped.length,
    },
  });
}

return output;

return $input.all().map((item) => {
  const warning = item.json.company_list_warning || null;
  const errors = Array.isArray(item.json.notification_errors) ? item.json.notification_errors.slice() : [];
  if (warning) errors.push(String(warning));
  return {
    json: {
      workflow: 'workflow_06b_career_page_monitor',
      status: 'completed',
      eval_run_id: item.json.run_id || null,
      job_ids: item.json.high_fit_jobs?.map((job) => job.job_id).filter(Boolean) || item.json.job_ids || [],
      result_count: Number(item.json.result_count || 0),
      high_fit_count: Number(item.json.high_fit_count || 0),
      notifications_sent: Number(item.json.notifications_sent || 0),
      notification_errors: errors,
      company_list_count: Number(item.json.company_list_count || 0),
      company_list_warning: warning,
      message: item.json.message || 'Evaluate + notify completed.',
    },
  };
});

return $input.all().map((item) => {
  const warning = item.json.company_list_warning || null;
  const errors = Array.isArray(item.json.errors) ? item.json.errors.slice() : [];
  if (warning) errors.push(String(warning));
  return {
    json: {
      workflow: 'workflow_06b_career_page_monitor',
      status: 'completed',
      new_jobs: 0,
      duplicates_skipped: Number(item.json.duplicates_skipped || 0),
      source_metrics: item.json.source_metrics || {},
      company_list_count: Number(item.json.company_list_count || 0),
      company_list_warning: warning,
      errors,
      message: item.json.message || 'Discovery run completed with no new jobs.',
    },
  };
});

return $input.all().map((item) => ({
  json: {
    workflow: 'workflow_06b_career_page_monitor',
    company: item.json.company?.name || 'unknown',
    status: 'no-matches',
    fetched_jobs: Number(item.json.fetched_jobs || 0),
    matched_jobs: Number(item.json.matched_jobs || 0),
    fetch_error: item.json.fetch_error || null,
    company_list_count: Number(item.json.company_list_count || 0),
    company_list_warning: item.json.company_list_warning || null,
    message: 'No matching jobs for configured title filters.',
  },
}));
